(function () {
  const CHARTJS_CDN = "https://cdn.jsdelivr.net/npm/chart.js@4.4.0/dist/chart.umd.min.js";
  const POLL_MODEL_MS = 2000;
  const CHART_COLORS = ["#0088FE", "#00C49F", "#FFBB28", "#FF8042", "#A020F0", "#FF6666", "#67C23A", "#4BC0C0", "#9966FF"];
  const BAR_CHART_PRIMARY_COLOR = "#007bff";
  let activeChartInstance = null;

  // --- Utility Functions ---
  async function loadScript(url) {
    return new Promise((resolve, reject) => {
      if (window.Chart) return resolve();
      const s = document.createElement("script");
      s.src = url;
      s.async = true;
      s.onload = () => resolve();
      s.onerror = e => reject(e);
      document.head.appendChild(s);
    });
  }
  function formatRawNumber(amount, decimals = 2) {
    if (amount === null || amount === undefined || amount === "") return "0.00";
    const num = Number(String(amount).replace(/,/g, ""));
    if (isNaN(num)) return String(amount);
    return num.toFixed(decimals).replace(/\B(?=(\d{3})+(?!\d))/g, ",");
  }
  function formatCurrency(amount) {
    if (amount === null || amount === undefined) return "$0.00";
    const num = Number(amount);
    if (isNaN(num)) return "$0.00";
    const sign = num < 0 ? "-" : "";
    const abs = Math.abs(num);
    return sign + "$" + abs.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ",");
  }
  function formatCurrencyCompact(amount) {
    if (amount === null || amount === undefined) return "$0";
    const num = Number(amount);
    if (isNaN(num)) return "$0";
    const sign = num < 0 ? "-" : "";
    const abs = Math.abs(num);
    if (abs >= 1e9) return `${sign}$${(abs / 1e9).toFixed(1)}B`;
    if (abs >= 1e6) return `${sign}$${(abs / 1e6).toFixed(1)}M`;
    if (abs >= 1e3) return `${sign}$${(abs / 1e3).toFixed(1)}K`;
    return `${sign}$${abs.toFixed(2)}`;
  }
  function normalizeUtilityData(arr) {
    if (!Array.isArray(arr)) return [];
    return arr.map(r => {
      const utility_type = r.utility_type ?? "UNKNOWN";
      const total_cost_raw = r.total_cost ?? r.totalCost ?? r.cost ?? r.value ?? 0;
      return {
        utility_type: String(utility_type),
        total_cost: Number(total_cost_raw)
      };
    });
  }
  function normalizeGenericRows(rows) {
    if (!Array.isArray(rows)) return [];
    return rows.map(r => {
      const out = {};
      for (const k in r) {
        const v = r[k];
        const cleaned = typeof v === "string" ? String(v).replace(/,/g, "") : v;
        const num = Number(cleaned);
        if (typeof v === "string" && !isNaN(num)) {
          out[k] = num;
        } else if (typeof v === "string" && isNaN(num)) {
          out[k] = v;
        } else if (typeof v === "number") {
          out[k] = v;
        } else {
          out[k] = v;
        }
      }
      return out;
    });
  }
  function displayChartContent(showChart, message = "No data for this chart.") {
    const canvas = document.getElementById("selected-chart-canvas");
    const overlay = document.getElementById("no-data-overlay");
    const overlayText = overlay ? overlay.querySelector('div') : null;
    if (canvas) canvas.style.display = showChart ? 'block' : 'none';
    if (overlay) {
      overlay.style.display = showChart ? 'none' : 'flex';
      overlay.style.alignItems = 'center';
      overlay.style.justifyContent = 'center';
    }
    if (overlayText) overlayText.textContent = message;
  }
  function formatTableValue(chartKey, column, value) {
    if (value === null || value === undefined || value === "") return "-";
    const num = Number(String(value).replace(/,/g, ""));
    const isNum = !isNaN(num);
    const key = String(chartKey || "").toLowerCase();
    const col = String(column || "").toLowerCase();
    if (key.includes("highest_unit_cost_locations") && (col.includes("unit_cost") || col.includes("unit") || col.includes("unitcost"))) {
      return isNum ? `${num.toFixed(2)} $/kWh` : value;
    }
    if (key.includes("highest_consumption_locations") || key.includes("monthly_consumption_by_location") || key.includes("monthly_consumption")) {
      return isNum ? `${formatRawNumber(num, 2)} kWh` : value;
    }
    // Default: just number (negatives preserved)
    return isNum ? formatRawNumber(num, 2) : value;
  }
  function renderChart(chartType, labels, datasets, chartTypeKey) {
    if (activeChartInstance) {
      try {
        activeChartInstance.destroy();
      } catch (e) {}
      activeChartInstance = null;
    }
    const canvas = document.getElementById("selected-chart-canvas");
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    displayChartContent(true);
    const chartKey = String(chartTypeKey || "").toLowerCase();
    const tooltipLabelCallback = context => {
      const raw = context.parsed && typeof context.parsed.y !== "undefined" ? context.parsed.y : context.parsed;
      const colLabel = context.dataset.label || "";
      if (chartKey.includes("highest_unit_cost_locations")) return `${colLabel ? colLabel + ": " : ""}${Number(raw).toFixed(4)} $/kWh`;
      if (chartKey.includes("highest_consumption_locations") || chartKey.includes("monthly_consumption_by_location") || chartKey.includes("monthly_consumption")) return `${colLabel ? colLabel + ": " : ""}${Number(raw).toFixed(2)} kWh`;
      return `${colLabel ? colLabel + ": " : ""}${formatRawNumber(raw, 2)}`;
    };
    const commonOptions = {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: {
          position: chartType === 'pie' ? "bottom" : "top",
          display: chartType === 'pie' || datasets.length > 1
        },
        tooltip: {
          callbacks: {
            label: tooltipLabelCallback,
            title: context => context[0]?.label || ""
          }
        }
      }
    };
    if (chartType === 'bar') {
      let yTitle = 'Value';
      let tickCallback = v => String(v);
      if (chartKey.includes("highest_unit_cost_locations")) {
        yTitle = "$ / kWh";
        tickCallback = v => Number(v).toFixed(4);
      } else if (chartKey.includes("highest_consumption_locations") || chartKey.includes("monthly_consumption_by_location") || chartKey.includes("monthly_consumption")) {
        yTitle = "kWh";
        tickCallback = v => formatRawNumber(v, 2) + " kWh";
      } else {
        yTitle = "USD";
        tickCallback = v => formatCurrencyCompact(v);
      }
      activeChartInstance = new window.Chart(ctx, {
        type: "bar",
        data: {
          labels,
          datasets
        },
        options: {
          ...commonOptions,
          scales: {
            y: {
              beginAtZero: true,
              title: {
                display: true,
                text: yTitle
              },
              ticks: {
                callback: tickCallback
              },
              grid: {
                color: 'rgba(0,0,0,0.05)'
              }
            },
            x: {
              grid: {
                display: false
              },
              ticks: {
                maxRotation: 90,
                minRotation: 90
              }
            }
          }
        }
      });
    } else if (chartType === 'pie') {
      activeChartInstance = new window.Chart(ctx, {
        type: "pie",
        data: {
          labels,
          datasets
        },
        options: commonOptions
      });
    }
  }
  function renderTable(rows, xKey, yKeys, chartTypeKey) {
    const tableBody = document.getElementById("data-table-body");
    if (!tableBody) return;
    if (!rows.length) {
      tableBody.innerHTML = '<div style="padding:15px;text-align:center;color:#666;">No Data to display in table.</div>';
      return;
    }
    const getHeaderName = key => key.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
    const columns = [xKey, ...yKeys];
    let html = '<table class="data-table"><thead><tr>';
    columns.forEach(k => html += `<th>${getHeaderName(k)}</th>`);
    html += '</tr></thead><tbody>';
    rows.forEach(row => {
      html += '<tr>';
      html += `<td>${row[xKey] ?? '-'}</td>`;
      yKeys.forEach(yKey => {
        html += `<td>${formatTableValue(chartTypeKey, yKey, row[yKey])}</td>`;
      });
      html += '</tr>';
    });
    html += '</tbody></table>';
    tableBody.innerHTML = html;
  }
  async function renderFullView() {
    const model = appsmith?.model;
    const chartConfig = model?.chart;
    const chartData = model?.chartData;
    if (!chartConfig || !chartData) {
      displayChartContent(false, "Waiting for chart configuration and data...");
      return;
    }
    const chartMap = {
      "cost_by_utility": "CostsbyUtilityType",
      "highest_unit_cost_locations": "HighestUnitCostLocations",
      "highest_cost_locations": "HighestCostLocations",
      "charges_by_vendor": "ChargesByVendor",
      "costs_by_charge_type": "CostsbyChargeType",
      "monthly_cost_by_location": "MonthlyCostbyLocation",
      "highest_consumption_locations": "HighestConsumptionLocations",
      "monthly_consumption_by_location": "MonthlyConsumptionbyLocation"
    };
    const chartTypeKey = chartConfig.type;
    const dataKey = chartMap[chartTypeKey] || chartTypeKey;
    let rows = chartData[dataKey] || [];
    if (!rows.length) {
      displayChartContent(false, "No data found for this chart.");
      renderTable([], 'x', [], chartTypeKey);
      return;
    }
    let labels = [],
      datasets = [],
      xKey = 'Description',
      yKeys = [],
      chartJsType = 'bar',
      finalRows = [];
    if (chartTypeKey === "cost_by_utility") {
      chartJsType = 'pie';
      const normalizedData = normalizeUtilityData(rows).sort((a, b) => b.total_cost - a.total_cost);
      const top = normalizedData.slice(0, 3).map(r => ({
        x: r.utility_type,
        y: r.total_cost
      }));
      const others = normalizedData.slice(3);
      if (others.length) top.push({
        x: "Others",
        y: others.reduce((sum, r) => sum + r.total_cost, 0)
      });
      labels = top.map(r => r.x);
      const values = top.map(r => r.y);
      const bgColors = labels.map((_, i) => CHART_COLORS[i % CHART_COLORS.length]);
      datasets.push({
        data: values,
        backgroundColor: bgColors
      });
      finalRows = normalizedData.map(r => ({
        utility_type: r.utility_type,
        total_cost: r.total_cost
      }));
      xKey = 'utility_type';
      yKeys = ['total_cost'];
    } else {
      chartJsType = 'bar';
      rows = normalizeGenericRows(rows);
      const sample = rows[0] || {};
      xKey = Object.keys(sample).find(k => ["location_description", "name", "vendor_name", "charge_type"].includes(k)) || Object.keys(sample)[0] || 'x';
      yKeys = Object.keys(sample).filter(k => k !== xKey && typeof sample[k] === "number");
      if (yKeys.length === 0) {
        displayChartContent(false, "No numeric data found for bar chart.");
        renderTable([], 'x', [], chartTypeKey);
        return;
      }
      let sortedRows = rows;
      if (yKeys.length === 1 && !chartTypeKey.toLowerCase().includes('monthly')) {
        const sortBy = yKeys[0];
        sortedRows = [...rows].sort((a, b) => (Number(b[sortBy]) || 0) - (Number(a[sortBy]) || 0));
      }
      labels = sortedRows.map(r => r[xKey]);
      finalRows = sortedRows;
      datasets = yKeys.map((yk, i) => ({
        label: yk.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase()),
        data: sortedRows.map(r => r[yk]),
        backgroundColor: yKeys.length > 1 ? CHART_COLORS[i % CHART_COLORS.length] : BAR_CHART_PRIMARY_COLOR
      }));
    }
    renderChart(chartJsType, labels, datasets, chartTypeKey);
    renderTable(finalRows, xKey, yKeys, chartTypeKey);
  }
  async function init() {
    try {
      await loadScript(CHARTJS_CDN);
    } catch (e) {
      console.error("Failed to load Chart.js:", e);
      return;
    }
    await renderFullView();
    let prevJson = JSON.stringify(appsmith?.model);
    setInterval(() => {
      try {
        const curr = appsmith?.model;
        const currJson = JSON.stringify(curr);
        if (currJson !== prevJson) {
          prevJson = currJson;
          renderFullView();
        }
      } catch (e) {
        console.error("Polling error:", e);
      }
    }, POLL_MODEL_MS);
  }
  appsmith.onReady(init);
})();

