            if (chartKey.includes("highest_unit_cost_locations")) { yTitle="$ / kWh"; tickCallback = v => Number(v).toFixed(4); }
            else if (chartKey.includes("highest_consumption_locations") || chartKey.includes("monthly_consumption_by_location") || chartKey.includes("monthly_consumption")) { yTitle="kWh"; tickCallback=v=>formatRawNumber(v,2)+" kWh"; }
            else { yTitle="USD"; tickCallback=v=>formatCurrencyCompact(v); }

            activeChartInstance = new window.Chart(ctx, {
                type: "bar",
                data: { labels, datasets },
                options: { ...commonOptions, scales: { y: { beginAtZero: true, title: { display: true, text: yTitle }, ticks: { callback: tickCallback }, grid: { color: 'rgba(0,0,0,0.05)' } }, x: { grid: { display:false }, ticks:{ maxRotation:90, minRotation:90 } } } }
            });
        } else if (chartType === 'pie') {
            activeChartInstance = new window.Chart(ctx, { type: "pie", data: { labels, datasets }, options: commonOptions });
        }
    }

    function renderTable(rows, xKey, yKeys, chartTypeKey) {
        const tableBody = document.getElementById("data-table-body");
        if (!tableBody) return;
        if (!rows.length) { tableBody.innerHTML='<div style="padding:15px;text-align:center;color:#666;">No Data to display in table.</div>'; return; }

        const getHeaderName = key => key.replace(/_/g,' ').replace(/\b\w/g,l=>l.toUpperCase());
        const columns = [xKey, ...yKeys];

        let html='<table class="data-table"><thead><tr>';
        columns.forEach(k=>html+=`<th>${getHeaderName(k)}</th>`); html+='</tr></thead><tbody>';

        rows.forEach(row=>{
            html+='<tr>';
            html+=`<td>${row[xKey] ?? '-'}</td>`;
            yKeys.forEach(yKey=>{ html+=`<td>${formatTableValue(chartTypeKey,yKey,row[yKey])}</td>` });
            html+='</tr>';
        });
        html+='</tbody></table>';
        tableBody.innerHTML = html;
    }

    async function renderFullView() {
        const model = appsmith?.model;
        const chartConfig = model?.chart;
        const chartData = model?.chartData;
        if (!chartConfig || !chartData) { displayChartContent(false,"Waiting for chart configuration and data..."); return; }

        const chartMap = {
            "cost_by_utility":"CostsbyUtilityType",
            "highest_unit_cost_locations":"HighestUnitCostLocations",
            "highest_cost_locations":"HighestCostLocations",
            "charges_by_vendor":"ChargesByVendor",
            "costs_by_charge_type":"CostsbyChargeType",
            "monthly_cost_by_location":"MonthlyCostbyLocation",
            "highest_consumption_locations":"HighestConsumptionLocations",
            "monthly_consumption_by_location":"MonthlyConsumptionbyLocation"
        };

        const chartTypeKey = chartConfig.type;
        const dataKey = chartMap[chartTypeKey] || chartTypeKey;
        let rows = chartData[dataKey] || [];
        if (!rows.length) { displayChartContent(false,"No data found for this chart."); renderTable([], 'x', [], chartTypeKey); return; }

        let labels=[], datasets=[], xKey='Description', yKeys=[], chartJsType='bar', finalRows=[];

        if(chartTypeKey==="cost_by_utility"){
            chartJsType='pie';
            const normalizedData=normalizeUtilityData(rows).sort((a,b)=>b.total_cost-a.total_cost);
            const top = normalizedData.slice(0,3).map(r=>({x:r.utility_type,y:r.total_cost}));
            const others = normalizedData.slice(3);
            if(others.length) top.push({x:"Others",y:others.reduce((sum,r)=>sum+r.total_cost,0)});
            labels = top.map(r=>r.x); const values = top.map(r=>r.y);
            const bgColors = labels.map((_,i)=>CHART_COLORS[i%CHART_COLORS.length]);
            datasets.push({ data:values, backgroundColor:bgColors });
            finalRows = normalizedData.map(r=>({ utility_type:r.utility_type, total_cost:r.total_cost }));
            xKey='utility_type'; yKeys=['total_cost'];
        } else {
            chartJsType='bar';
            rows=normalizeGenericRows(rows);
            const sample = rows[0]||{};
            xKey = Object.keys(sample).find(k=>["location_description","name","vendor_name","charge_type"].includes(k))||Object.keys(sample)[0]||'x';
            yKeys = Object.keys(sample).filter(k=>k!==xKey && typeof sample[k]==="number");
            if(yKeys.length===0){ displayChartContent(false,"No numeric data found for bar chart."); renderTable([], 'x', [], chartTypeKey); return; }
            let sortedRows = rows;
            if(yKeys.length===1 && !chartTypeKey.toLowerCase().includes('monthly')){
                const sortBy=yKeys[0]; sortedRows=[...rows].sort((a,b)=> (Number(b[sortBy])||0)-(Number(a[sortBy])||0));
            }
            labels = sortedRows.map(r=>r[xKey]);
            finalRows = sortedRows;
            datasets = yKeys.map((yk,i)=>({ label: yk.replace(/_/g,' ').replace(/\b\w/g,l=>l.toUpperCase()), data:sortedRows.map(r=>r[yk]), backgroundColor:(yKeys.length>1)?CHART_COLORS[i%CHART_COLORS.length]:BAR_CHART_PRIMARY_COLOR }));
        }

        renderChart(chartJsType, labels, datasets, chartTypeKey);
        renderTable(finalRows, xKey, yKeys, chartTypeKey);
    }

    async function init() {
        try { await loadScript(CHARTJS_CDN); } catch(e){ console.error("Failed to load Chart.js:",e); return; }
        await renderFullView();
        let prevJson = JSON.stringify(appsmith?.model);
        setInterval(()=>{
            try {
                const curr=appsmith?.model; const currJson=JSON.stringify(curr);
                if(currJson!==prevJson){ prevJson=currJson; renderFullView(); }
            }catch(e){console.error("Polling error:",e);}
        }, POLL_MODEL_MS);
    }

    appsmith.onReady(init);
})();
